import React, { useState, useContext, useEffect, useCallback } from "react";
import { Link } from "react-router-dom";
import "./GalleryPage.scss";
import { photographySection, greeting, socialMediaLinks } from "../../portfolio";
import StyleContext from "../../contexts/StyleContext";
import ToggleSwitch from "../../components/ToggleSwitch/ToggleSwitch";

export default function GalleryPage() {
    const { isDark } = useContext(StyleContext);
    const [selectedImage, setSelectedImage] = useState(null);
    const [loadedImages, setLoadedImages] = useState({});
    const [visibleItems, setVisibleItems] = useState(new Set());
    const [activeTag, setActiveTag] = useState("All");
    const [showInfo, setShowInfo] = useState(true);
    const [isFullscreen, setIsFullscreen] = useState(false);
    const [touchStart, setTouchStart] = useState(null);
    const [touchEnd, setTouchEnd] = useState(null);
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [avatarError, setAvatarError] = useState(false);
    const [lightboxLoaded, setLightboxLoaded] = useState(false);

    const images = photographySection.images;
    const tags = ["All", ...Array.from(new Set(images.flatMap(img => img.tags || []).filter(t => t !== "All")))];
    const filteredImages = activeTag === "All"
        ? images
        : images.filter(image => image.tags && image.tags.includes(activeTag));

    useEffect(() => {
        const handleFullscreenChange = () => {
            setIsFullscreen(!!document.fullscreenElement);
        };
        document.addEventListener('fullscreenchange', handleFullscreenChange);
        return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
    }, []);

    const toggleFullScreen = async () => {
        try {
            if (!document.fullscreenElement) {
                await document.documentElement.requestFullscreen();
            } else {
                if (document.exitFullscreen) {
                    await document.exitFullscreen();
                }
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleTouchStart = (e) => {
        setTouchEnd(null);
        setTouchStart(e.targetTouches[0].clientX);
    };

    const handleTouchMove = (e) => {
        setTouchEnd(e.targetTouches[0].clientX);
    };

    const handleTouchEnd = () => {
        if (!touchStart || !touchEnd) return;
        const distance = touchStart - touchEnd;
        const isLeftSwipe = distance > 50;
        const isRightSwipe = distance < -50;
        
        if (isLeftSwipe) {
            setSelectedImage(prev => (prev + 1) % filteredImages.length);
        }
        if (isRightSwipe) {
            setSelectedImage(prev => (prev - 1 + filteredImages.length) % filteredImages.length);
        }
    };

    // Intersection observer for fade-in on scroll
    useEffect(() => {
        setVisibleItems(new Set());

        // Small delay to let DOM update after filter change
        const timeout = setTimeout(() => {
            const observer = new IntersectionObserver(
                entries => {
                    entries.forEach(entry => {
                        if (entry.isIntersecting) {
                            setVisibleItems(prev => new Set([...prev, entry.target.dataset.index]));
                        }
                    });
                },
                { threshold: 0.1, rootMargin: "50px" }
            );

            const items = document.querySelectorAll(".gallery-item");
            items.forEach(item => observer.observe(item));

            return () => observer.disconnect();
        }, 50);

        return () => clearTimeout(timeout);
    }, [activeTag]);

    // Keyboard navigation for lightbox
    const handleKeyDown = useCallback(
        e => {
            if (selectedImage === null) return;
            if (e.key === "Escape") {
                setSelectedImage(null);
                if (document.fullscreenElement) {
                    document.exitFullscreen().catch(err => console.error(err));
                }
            }
            if (e.key === "ArrowRight")
                setSelectedImage(prev => (prev + 1) % filteredImages.length);
            if (e.key === "ArrowLeft")
                setSelectedImage(prev => (prev - 1 + filteredImages.length) % filteredImages.length);
        },
        [selectedImage, filteredImages.length]
    );

    useEffect(() => {
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [handleKeyDown]);

    // Reset lightbox loading state when image changes
    useEffect(() => {
        if (selectedImage !== null) {
            setLightboxLoaded(false);
        }
    }, [selectedImage]);

    // Lock body scroll when lightbox is open
    useEffect(() => {
        if (selectedImage !== null) {
            document.body.style.overflow = "hidden";
        } else {
            document.body.style.overflow = "";
        }
        return () => {
            document.body.style.overflow = "";
        };
    }, [selectedImage]);

    const handleImageLoad = index => {
        setLoadedImages(prev => ({ ...prev, [index]: true }));
    };

    if (!photographySection.display) return null;

    return (
        <div className={isDark ? "dark-mode gallery-root" : "gallery-root"}>
            {/* Navigation Bar */}
            <nav className={`gallery-nav ${isDark ? "dark" : ""}`}>
                <div className="gallery-nav-header">
                    <Link to="/" className="gallery-nav-logo">
                        <span className="grey-color">&lt;</span>
                        <span className="logo-name">{greeting.username}</span>
                        <span className="grey-color">/&gt;</span>
                    </Link>
                    <button 
                        className="gallery-hamburger-btn" 
                        onClick={() => setIsMenuOpen(!isMenuOpen)}
                        aria-label="Toggle Menu"
                    >
                        <span className={`hamburger-line ${isMenuOpen ? "open" : ""}`}></span>
                        <span className={`hamburger-line ${isMenuOpen ? "open" : ""}`}></span>
                        <span className={`hamburger-line ${isMenuOpen ? "open" : ""}`}></span>
                    </button>
                </div>
                <div className={`gallery-nav-links ${isMenuOpen ? "open" : ""}`}>
                    <Link to="/" className="gallery-nav-link" onClick={() => setIsMenuOpen(false)}>
                        Portfolio
                    </Link>
                    <span className="gallery-nav-link active" onClick={() => setIsMenuOpen(false)}>Photography</span>
                    <ToggleSwitch />
                </div>
            </nav>

            {/* Profile Header */}
            <header className="gallery-profile">
                <div className="gallery-profile-avatar-ring">
                    <div className="gallery-profile-avatar">
                        {!avatarError ? (
                            <img 
                                src="https://avatars.githubusercontent.com/u/25872488" 
                                alt={greeting.username}
                                className="gallery-profile-avatar-img"
                                onError={() => setAvatarError(true)}
                            />
                        ) : (
                            <span className="gallery-profile-avatar-text">
                                {greeting.username
                                    .split(" ")
                                    .map(n => n[0])
                                    .join("")}
                            </span>
                        )}
                    </div>
                </div>
                <div className="gallery-profile-info">
                    <div className="gallery-profile-name-row">
                        <h1 className="gallery-profile-name">{greeting.username}</h1>
                        {socialMediaLinks.instagram && (
                            <a
                                href={socialMediaLinks.instagram}
                                target="_blank"
                                rel="noreferrer"
                                className="gallery-follow-btn"
                            >
                                Follow
                            </a>
                        )}
                    </div>
                    <div className="gallery-profile-stats">
                        <span className="gallery-stat">
                            <strong>{images.length}</strong> posts
                        </span>
                    </div>
                    <p className="gallery-profile-bio">
                        {photographySection.subtitle}
                    </p>
                </div>
            </header>

            {/* Category Tabs */}
            {tags.length > 1 && (
                    <div className="gallery-tabs">
                        {tags.map((tag, i) => (
                            <span
                                key={i}
                                className={`gallery-tab ${activeTag === tag ? "active" : ""}`}
                                onClick={() => setActiveTag(tag)}
                            >
                                {tag}
                            </span>
                        ))}
                    </div>
                )}

            {/* Photo Grid */}
            <div className="gallery-grid">
                {filteredImages.map((image, index) => (
                    <div
                        key={index}
                        className={`gallery-item ${visibleItems.has(String(index)) ? "visible" : ""
                            }`}
                        data-index={index}
                        onClick={() => setSelectedImage(index)}
                    >
                        <div className="gallery-item-skeleton" />
                        <img
                            src={image.thumb || image.src}
                            alt={image.caption || `Photo ${index + 1}`}
                            className={`gallery-item-img ${loadedImages[index] ? "loaded" : ""
                                }`}
                            loading="lazy"
                            onLoad={() => handleImageLoad(index)}
                        />
                        <div className="gallery-item-overlay">
                            <div className="gallery-item-overlay-content">
                                {image.caption && (
                                    <p className="gallery-item-caption">{image.caption}</p>
                                )}
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Lightbox */}
            {selectedImage !== null && (
                <div
                    className="gallery-lightbox"
                    onClick={() => setSelectedImage(null)}
                    onTouchStart={handleTouchStart}
                    onTouchMove={handleTouchMove}
                    onTouchEnd={handleTouchEnd}
                >
                    <div
                        className="gallery-lightbox-content"
                        onClick={e => e.stopPropagation()}
                    >
                        <button
                            className="gallery-lightbox-fullscreen"
                            onClick={toggleFullScreen}
                            aria-label="Toggle Fullscreen"
                            title="Toggle Fullscreen"
                        >
                            <svg viewBox="0 0 24 24" width="20" height="20" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
                                {isFullscreen ? (
                                    <>
                                        <path d="M8 3v3a2 2 0 0 1-2 2H3m18 0h-3a2 2 0 0 1-2-2V3m0 18v-3a2 2 0 0 1 2-2h3M3 16h3a2 2 0 0 1 2 2v3"></path>
                                    </>
                                ) : (
                                    <>
                                        <path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"></path>
                                    </>
                                )}
                            </svg>
                        </button>
                        <button
                            className="gallery-lightbox-close"
                            onClick={() => {
                                setSelectedImage(null);
                                if (document.fullscreenElement) {
                                    document.exitFullscreen().catch(err => console.error(err));
                                }
                            }}
                            aria-label="Close"
                        >
                            ✕
                        </button>
                        <button
                            className="gallery-lightbox-nav prev"
                            onClick={() =>
                                setSelectedImage(
                                    prev => (prev - 1 + filteredImages.length) % filteredImages.length
                                )
                            }
                            aria-label="Previous"
                        >
                            ‹
                        </button>
                        {!lightboxLoaded && (
                            <div className="gallery-lightbox-spinner">
                                <div className="spinner-ring" />
                            </div>
                        )}
                        <img
                            src={filteredImages[selectedImage].src}
                            alt={
                                filteredImages[selectedImage].caption ||
                                `Photo ${selectedImage + 1}`
                            }
                            className={`gallery-lightbox-img ${lightboxLoaded ? "loaded" : ""}`}
                            onLoad={() => setLightboxLoaded(true)}
                        />
                        <button
                            className="gallery-lightbox-nav next"
                            onClick={() =>
                                setSelectedImage(prev => (prev + 1) % filteredImages.length)
                            }
                            aria-label="Next"
                        >
                            ›
                        </button>
                        {filteredImages[selectedImage].caption && (
                            <div className={`gallery-lightbox-info ${!showInfo ? 'minimized' : ''}`} onClick={e => e.stopPropagation()}>
                                <button
                                    className="gallery-panel-close-btn"
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        setShowInfo(false);
                                    }}
                                    aria-label="Minimize Info"
                                    title="Minimize"
                                >
                                    <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" strokeWidth="3" fill="none" strokeLinecap="round" strokeLinejoin="round">
                                        <polyline points="6 9 12 15 18 9"></polyline>
                                    </svg>
                                </button>
                                <h3 className="gallery-lightbox-title">{filteredImages[selectedImage].caption}</h3>
                                <div className="gallery-lightbox-meta">
                                    {filteredImages[selectedImage].date && (
                                        <span className="meta-item">📅 {filteredImages[selectedImage].date}</span>
                                    )}
                                    {filteredImages[selectedImage].location && (
                                        <span className="meta-item">📍 {filteredImages[selectedImage].location}</span>
                                    )}
                                    {filteredImages[selectedImage].camera && (
                                        <span className="meta-item">📷 {filteredImages[selectedImage].camera}</span>
                                    )}
                                </div>
                                {filteredImages[selectedImage].tags && (
                                    <div className="gallery-lightbox-tags">
                                        {filteredImages[selectedImage].tags.map((tag, i) => (
                                            <span key={i} className="meta-tag">{tag}</span>
                                        ))}
                                    </div>
                                )}
                            </div>
                        )}
                        <div className="gallery-lightbox-bottom-bar" onClick={e => e.stopPropagation()}>
                            {filteredImages[selectedImage].caption && (
                                <button
                                    className={`gallery-panel-open-btn ${showInfo ? 'hidden' : ''}`}
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        setShowInfo(true);
                                    }}
                                    aria-label="Show Info"
                                    title="Show Info"
                                >
                                    <svg viewBox="0 0 24 24" width="20" height="20" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="12" cy="12" r="10"></circle>
                                        <line x1="12" y1="16" x2="12" y2="12"></line>
                                        <line x1="12" y1="8" x2="12.01" y2="8"></line>
                                    </svg>
                                </button>
                            )}
                            <div className="gallery-lightbox-counter">
                                {selectedImage + 1} / {filteredImages.length}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Footer */}
            <footer className="gallery-footer">
                <p>
                    © {new Date().getFullYear()} {greeting.username} · Photography
                </p>
            </footer>
        </div>
    );
}
